function findProvider(context, chain, operation = 'earn') {
    let fallback;
    for (const provider of context.providers){
        fallback ??= provider;
        if (provider.supportedChains.length === 0) continue;
        if (chain === undefined || provider.supportedChains.some((c)=>c.chain === chain.chain)) {
            return provider;
        }
    }
    if (fallback === undefined) {
        throw createValidationFailedError('context.providers', [], 'No earn providers configured');
    }
    if (chain !== undefined) {
        throw createUnsupportedEarnRouteError(operation, chain.name);
    }
    return fallback;
}

