    const sourceAddress = await resolveAdapterAddress(params.from, sourceChain);
    const baseParams = {
        from: {
            ...params.from,
            chain: sourceChain,
            address: sourceAddress
        },
        vaultAddress: params.vaultAddress,
        amount: params.amount,
        ...params.config !== undefined && {
            config: params.config
        }
    };
